#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>

int main() {
 int fd; // file descriptor
 char buffer[100];
 ssize_t bytes_read;

 // Open file (system call)
 fd = open("example.txt", O_RDONLY);
 if (fd < 0) {
 perror("open");
 return 1;
 }

 // Read from file (system call)
 bytes_read = read(fd, buffer, sizeof(buffer) - 1);
 if (bytes_read < 0) {
 perror("read");
 close(fd);
 return 1;
 }

 buffer[bytes_read] = '\0'; // Null terminate
 printf("Read %zd bytes: %s\n", bytes_read, buffer);

 // Close file (system call)
 close(fd);
 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>

int main() {
 pid_t pid;
 int x = 10;

 printf("Before fork: x = %d\n", x);

 pid = fork(); // Creates new process

 if (pid < 0) {
 // Error occurred
 perror("fork failed");
 return 1;
 }
 else if (pid == 0) {
 // Child process
 x = 20;
 printf("Child: PID = %d, Parent PID = %d, x = %d\n", 
 getpid(), getppid(), x);
 }
 else {
 // Parent process
 printf("Parent: PID = %d, Child PID = %d, x = %d\n", 
 getpid(), pid, x);
 }

 printf("After fork: x = %d\n", x);
 return 0;
}
